from flask import Flask, request, session, redirect, url_for
import xml.etree.ElementTree as ET

app = Flask(__name__)
app.secret_key = 'your-secret-key'

# Function to parse SAML XML responses
def parse_saml_response(response):
    try:
        root = ET.fromstring(response)
        return root
    except ET.ParseError:
        return None

# Function to extract user attributes from Assertion elements
def get_user_attributes(assertion):
    attrs = {}
    for element in assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
        attr_name = element.attrib['Name']
        values = [value.text for value in element.findall('{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')]
        attrs[attr_name] = values
    return attrs

# Function to create user sessions
def create_user_session(user_id, user_attributes):
    session['user_id'] = user_id
    session['attributes'] = user_attributes

# Route for SAML POST response from Identity Provider
@app.route('/saml/SSO', methods=['POST'])
def sso():
    saml_response = request.form.get('SAMLResponse')
    if not saml_response:
        return 'No SAML Response received', 400
    
    assertion = parse_saml_response(saml_response)
    if assertion is None or not hasattr(assertion, 'findall'):
        return 'Invalid SAML Response', 400
    
    # Extract user attributes from Assertion elements
    user_attributes = get_user_attributes(assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion'))
    
    if not user_attributes:
        return 'No user attributes found', 400
    
    create_user_session(user_id=user_attributes['uid'][0], user_attributes=user_attributes)
    
    # Return HTTP redirect to protected resource
    return redirect(url_for('protected_resource'))

# Route for protected resource (e.g. Dashboard or other sensitive area)
@app.route('/protected')
def protected_resource():
    if 'user_id' not in session:
        return 'You do not have access to this page', 403
    
    # You can add code here to authenticate the user
    return 'Welcome, {}!'.format(session['attributes']['uid'][0])

